fun solve(nums: Array<Long>, queries: Array<Array<Long>>): Array<Long> {
    val ans = mutableListOf<Long>()
    for (query in queries) {
        val l = query[0].toInt()
        val r = query[1].toInt()
        val threshold = query[2]
        val freq = mutableMapOf<Long, Int>()
        for (i in l..r) {
            val num = nums[i]
            freq[num] = freq.getOrDefault(num, 0) + 1
        }
        val candidates = mutableListOf<Pair<Int, Long>>()
        for ((num, count) in freq) {
            if (count >= threshold) {
                candidates.add(Pair(-count, num))
            }
        }
        if (candidates.isEmpty()) {
            ans.add(-1)
        } else {
            candidates.sortWith(compareBy({ it.first }, { it.second }))
            ans.add(candidates[0].second)
        }
    }
    return ans.toTypedArray()
}
